#include <stdio.h>
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    int min_val = A[0];
    int max_val = A[0];
    for (int i = 1; i < N; i++) {
        if (A[i] < min_val) {
            min_val = A[i];
        }
        if (A[i] > max_val) {
            max_val = A[i];
        }
    }
    for (int i = 0; i < Q; i++) {
        int t;
        scanf("%d", &t);
        if (t >= min_val && t <= max_val) {
            printf("Yes\n");
        } else {
            printf("No\n");
        }
    }
    return 0;
}

