import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int Q = sc.nextInt();
        int[] A = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = sc.nextInt();
        }
        int min_val = A[0];
        int max_val = A[0];
        for (int i = 1; i < N; i++) {
            if (A[i] < min_val) {
                min_val = A[i];
            }
            if (A[i] > max_val) {
                max_val = A[i];
            }
        }
        for (int i = 0; i < Q; i++) {
            int t = sc.nextInt();
            if (t >= min_val && t <= max_val) {
                System.out.println("Yes");
            } else {
                System.out.println("No");
            }
        }
    }
}

